    Supports dictionary key traversal and array index access. Gracefully handles 
    missing keys/indices by returning None. Detects circular references to prevent 
    infinite loops during traversal.

    Args:
        data: The root JSON-like object (dict, list, tuple, or primitive).
        path: A string path using dot notation and optional array indexing.
              Valid formats: "user.profile", "items[0].name", "data.config[2].enabled"

    Returns:
        JSONPathResult: A typed result containing the extracted value, an optional 
                        error message for debugging, and a success flag.

    Examples:
        >>> data = {"users": [{"name": "Alice", "settings": {"theme": "dark"}}]}
        >>> parse_json_path(data, "users[0].settings.theme")
        JSONPathResult(value='dark', error=None, success=True)

        >>> parse_json_path(data, "users[1].name")  # Missing index
        JSONPathResult(value=None, error=None, success=True)

        >>> parse_json_path(data, "users.name")     # Type mismatch
        JSONPathResult(value=None, error="Expected dict at key 'name', but got list", success=False)
    """
    if not isinstance(path, str):
        return JSONPathResult(error="Path argument must be a string.", success=False)

