                return JSONPathResult(
                    error=f"Circular reference detected at path segment '{token}'",
                    success=False
                )
            seen_ids.add(obj_id)

        # JSON null maps to Python None. Cannot traverse further from null.
        if current is None:
            return JSONPathResult(value=None)

        if isinstance(token, str):
            if not isinstance(current, dict):
