                return JSONPathResult(
                    error=f"Expected list at index {token}, but got {type(current).__name__}",
                    success=False
                )
            # Graceful out-of-bounds handling
            if token < 0 or token >= len(current):
                return JSONPathResult(value=None)
            current = current[token]

